1	import {
2	  CODEX_REASONING_EFFORT_OPTIONS,
3	  DEFAULT_MODEL_BY_PROVIDER,
4	  MODEL_OPTIONS_BY_PROVIDER,
5	  MODEL_SLUG_ALIASES_BY_PROVIDER,
6	  type CodexReasoningEffort,
7	  type ModelSlug,
8	  type ProviderKind,
9	} from "@t3tools/contracts";
10	
11	type CatalogProvider = keyof typeof MODEL_OPTIONS_BY_PROVIDER;
12	
13	const MODEL_SLUG_SET_BY_PROVIDER: Record<CatalogProvider, ReadonlySet<ModelSlug>> = {
14	  codex: new Set(MODEL_OPTIONS_BY_PROVIDER.codex.map((option) => option.slug)),
15	};
16	
17	export function getModelOptions(provider: ProviderKind = "codex") {
18	  return MODEL_OPTIONS_BY_PROVIDER[provider];
19	}
20	
21	export function getDefaultModel(provider: ProviderKind = "codex"): ModelSlug {
22	  return DEFAULT_MODEL_BY_PROVIDER[provider];
23	}
24	
25	export function normalizeModelSlug(
26	  model: string | null | undefined,
27	  provider: ProviderKind = "codex",
28	): ModelSlug | null {
29	  if (typeof model !== "string") {
30	    return null;
31	  }
32	
33	  const trimmed = model.trim();
34	  if (!trimmed) {
35	    return null;
36	  }
37	
38	  const aliases = MODEL_SLUG_ALIASES_BY_PROVIDER[provider] as Record<string, ModelSlug>;
39	  const aliased = aliases[trimmed];
40	  return typeof aliased === "string" ? aliased : (trimmed as ModelSlug);
41	}
42	
43	export function resolveModelSlug(
44	  model: string | null | undefined,
45	  provider: ProviderKind = "codex",
46	): ModelSlug {
47	  const normalized = normalizeModelSlug(model, provider);
48	  if (!normalized) {
49	    return getDefaultModel(provider);
50	  }
51	
52	  return MODEL_SLUG_SET_BY_PROVIDER[provider].has(normalized)
53	    ? normalized
54	    : getDefaultModel(provider);
55	}
56	
57	export function resolveModelSlugForProvider(
58	  provider: ProviderKind,
59	  model: string | null | undefined,
60	): ModelSlug {
61	  return resolveModelSlug(model, provider);
62	}
63	
64	export function getReasoningEffortOptions(
65	  provider: ProviderKind = "codex",
66	): ReadonlyArray<CodexReasoningEffort> {
67	  return provider === "codex" ? CODEX_REASONING_EFFORT_OPTIONS : [];
68	}
69	
70	export function getDefaultReasoningEffort(provider: "codex"): CodexReasoningEffort;
71	export function getDefaultReasoningEffort(provider: ProviderKind): CodexReasoningEffort | null;
72	export function getDefaultReasoningEffort(
73	  provider: ProviderKind = "codex",
74	): CodexReasoningEffort | null {
75	  return provider === "codex" ? "high" : null;
76	}
77	
78	export { CODEX_REASONING_EFFORT_OPTIONS };
