152	  provider: ProviderKind,
153	  customModels: readonly string[],
154	  selectedModel: string | null | undefined,
155	): string {
156	  const options = getAppModelOptions(provider, customModels, selectedModel);
157	  const trimmedSelectedModel = selectedModel?.trim();
158	  if (trimmedSelectedModel) {
159	    const direct = options.find((option) => option.slug === trimmedSelectedModel);
160	    if (direct) {
161	      return direct.slug;
162	    }
163	
164	    const byName = options.find(
165	      (option) => option.name.toLowerCase() === trimmedSelectedModel.toLowerCase(),
166	    );
167	    if (byName) {
168	      return byName.slug;
169	    }
170	  }
171	
172	  const normalizedSelectedModel = normalizeModelSlug(selectedModel, provider);
173	  if (!normalizedSelectedModel) {
174	    return getDefaultModel(provider);
175	  }
176	
177	  return (
178	    options.find((option) => option.slug === normalizedSelectedModel)?.slug ??
179	    getDefaultModel(provider)
180	  );
181	}
