import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  DEFAULT_THEME_ID,
  getTheme,
  listThemes,
  type Theme,
  type ThemeColors,
} from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:theme";

// ---------------------------------------------------------------------------
// CSS custom-property mapping
// ---------------------------------------------------------------------------

const COLOR_CSS_PROPERTIES: ReadonlyArray<readonly [keyof ThemeColors, string]> = [
  ["background", "--t3-background"],
  ["foreground", "--t3-foreground"],
  ["accent", "--t3-accent"],
  ["sidebar", "--t3-sidebar"],
  ["editor", "--t3-editor"],
  ["terminal", "--t3-terminal"],
  ["statusBar", "--t3-status-bar"],
];

// ---------------------------------------------------------------------------
// Module-level external store (shared across all hook consumers)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];

interface ThemeSnapshot {
  themeId: string;
}

let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

/**
 * Read the persisted theme id.
 *
 * Handles legacy values ("light", "dark", "system") written by the previous
 * light/dark/system toggle so existing users get a smooth migration.
 */
function getStoredThemeId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (!raw) return DEFAULT_THEME_ID;

  // Migrate legacy values
  if (raw === "light") return "t3-light";
  if (raw === "dark" || raw === "system") return "t3-dark";

  // Validate that the stored id maps to a real theme
  if (getTheme(raw)) return raw;
  return DEFAULT_THEME_ID;
}

function resolveTheme(id: string): Theme {
  return getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
}

// ---------------------------------------------------------------------------
// DOM side-effects
// ---------------------------------------------------------------------------

function applyTheme(theme: Theme, suppressTransitions = false) {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Toggle dark / light mode class (consumed by Tailwind dark variant + scrollbar CSS)
  root.classList.toggle("dark", theme.isDark);

  // Apply theme color custom properties
  for (const [colorKey, cssProperty] of COLOR_CSS_PROPERTIES) {
    root.style.setProperty(cssProperty, theme.colors[colorKey]);
  }
  root.style.setProperty("--t3-font-family", theme.fontFamily);
  root.style.setProperty("--t3-font-size", `${theme.fontSize}px`);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash of wrong theme
applyTheme(resolveTheme(getStoredThemeId()));

// ---------------------------------------------------------------------------
// useSyncExternalStore plumbing
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const themeId = getStoredThemeId();

  if (lastSnapshot && lastSnapshot.themeId === themeId) {
    return lastSnapshot;
  }

  lastSnapshot = { themeId };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(resolveTheme(getStoredThemeId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Public hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = resolveTheme(snapshot.themeId);

  /** "light" | "dark" — useful for components that only care about the mode. */
  const resolvedTheme: "light" | "dark" = theme.isDark ? "dark" : "light";

  const availableThemes = listThemes();

  const setTheme = useCallback((id: string) => {
    localStorage.setItem(STORAGE_KEY, id);
    applyTheme(resolveTheme(id), true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount / when theme object identity changes
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, resolvedTheme, availableThemes } as const;
}

