1	/** Color slots that every theme must define. */
2	export interface ThemeColors {
3	  readonly background: string;
4	  readonly foreground: string;
5	  readonly accent: string;
6	  readonly sidebar: string;
7	  readonly editor: string;
8	  readonly terminal: string;
9	  readonly statusBar: string;
10	}
11	
12	/** A complete theme definition. */
13	export interface Theme {
14	  readonly id: string;
15	  readonly name: string;
16	  /** Whether the theme should activate dark-mode CSS (`.dark` class on root). */
17	  readonly isDark: boolean;
18	  readonly colors: ThemeColors;
19	  readonly fontFamily: string;
20	  readonly fontSize: number;
21	}
22	
23	// ---------------------------------------------------------------------------
24	// Built-in themes
25	// ---------------------------------------------------------------------------
26	
27	const SHARED_FONT_FAMILY =
