/** Color slots that every theme must define. */
export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

/** A complete theme definition. */
export interface Theme {
  readonly id: string;
  readonly name: string;
  /** Whether the theme should activate dark-mode CSS (`.dark` class on root). */
  readonly isDark: boolean;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

const SHARED_FONT_FAMILY =
  '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';

const builtInThemes: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    isDark: true,
    colors: {
      background: "#0a0a0a",
      foreground: "#f5f5f5",
      accent: "#a78bfa",
      sidebar: "#111111",
      editor: "#0a0a0a",
      terminal: "#0c0c0c",
      statusBar: "#111111",
    },
    fontFamily: SHARED_FONT_FAMILY,
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    isDark: false,
    colors: {
      background: "#ffffff",
      foreground: "#262626",
      accent: "#7c3aed",
      sidebar: "#fafafa",
      editor: "#ffffff",
      terminal: "#f5f5f5",
      statusBar: "#f0f0f0",
    },
    fontFamily: SHARED_FONT_FAMILY,
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    isDark: true,
    colors: {
      background: "#0b1120",
      foreground: "#e2e8f0",
      accent: "#38bdf8",
      sidebar: "#0f172a",
      editor: "#0b1120",
      terminal: "#0d1526",
      statusBar: "#0f172a",
    },
    fontFamily: SHARED_FONT_FAMILY,
    fontSize: 14,
  },
];

// ---------------------------------------------------------------------------
// Lookup helpers
// ---------------------------------------------------------------------------

const themeMap = new Map<string, Theme>(builtInThemes.map((t) => [t.id, t]));

/** Return a theme by `id`, or `undefined` if no match. */
export function getTheme(id: string): Theme | undefined {
  return themeMap.get(id);
}

/** Return every registered built-in theme. */
export function listThemes(): readonly Theme[] {
  return builtInThemes;
}

/** The default theme id used when nothing is persisted yet. */
export const DEFAULT_THEME_ID = "t3-dark";

